"""Parity + correctness test for the lattice_vq wheel.

1. Imports the maturin-built wheel.
2. Round-trip / idempotency: Q(x) is a valid lattice point and Q(Q(x)) == Q(x).
3. E8 parity: wheel nearest_e8_batch output == TS reference port (exact).
4. quant_error_batch_* == ||x - Q(x)||^2 recomputed in numpy (exact tie-in).
"""
import json
import os
import sys
import numpy as np

import lattice_vq as lvq

HERE = os.path.dirname(os.path.abspath(__file__))
fails = []


def load(name):
    with open(os.path.join(HERE, name)) as f:
        return json.load(f)


# ---- E8 parity vs TS reference port ----
e8_in = np.array(load("golden_e8.json"), dtype=np.float64)
ts_exp = load("ts_e8_expected.json")
ts_q = np.array([r["q"] for r in ts_exp], dtype=np.int64)
ts_err = np.array([r["err"] for r in ts_exp], dtype=np.float64)

wheel_q = lvq.nearest_e8_batch(e8_in)
wheel_err = lvq.quant_error_batch_e8(e8_in)

if wheel_q.dtype != np.int64:
    fails.append(f"E8 dtype {wheel_q.dtype} != int64")
if wheel_q.shape != (e8_in.shape[0], 8):
    fails.append(f"E8 shape {wheel_q.shape}")
if not np.array_equal(wheel_q, ts_q):
    diff = np.where(np.any(wheel_q != ts_q, axis=1))[0]
    fails.append(f"E8 PARITY mismatch vs TS at rows {diff.tolist()}")
else:
    print(f"[ok] E8 parity vs TS port: {len(ts_q)}/{len(ts_q)} rows EXACT match")

# error parity: wheel error == TS error == numpy recompute
np_err_e8 = np.sum((e8_in - wheel_q.astype(np.float64)) ** 2, axis=1)
if not np.allclose(wheel_err, ts_err, atol=1e-9):
    fails.append("E8 quant_error != TS error")
elif not np.allclose(wheel_err, np_err_e8, atol=1e-9):
    fails.append("E8 quant_error != numpy ||x-Q(x)||^2")
else:
    print(f"[ok] E8 quant_error matches TS + numpy recompute")

# E8 idempotency
e8_q2 = lvq.nearest_e8_batch(wheel_q.astype(np.float64))
if not np.array_equal(e8_q2, wheel_q):
    fails.append("E8 NOT idempotent: Q(Q(x)) != Q(x)")
else:
    print(f"[ok] E8 idempotent: Q(Q(x)) == Q(x)")


# ---- Leech: idempotency + error tie-in (no TS port exists for Leech) ----
leech_in = np.array(load("golden_leech.json"), dtype=np.float64)
leech_q = lvq.nearest_leech_batch(leech_in)
leech_err = lvq.quant_error_batch_leech(leech_in)

if leech_q.dtype != np.int64:
    fails.append(f"Leech dtype {leech_q.dtype} != int64")
if leech_q.shape != (leech_in.shape[0], 24):
    fails.append(f"Leech shape {leech_q.shape}")

# error tie-in
np_err_leech = np.sum((leech_in - leech_q.astype(np.float64)) ** 2, axis=1)
if not np.allclose(leech_err, np_err_leech, atol=1e-9):
    fails.append("Leech quant_error != numpy ||x-Q(x)||^2")
else:
    print(f"[ok] Leech quant_error matches numpy recompute")

# Leech idempotency (lattice points map to themselves)
leech_q2 = lvq.nearest_leech_batch(leech_q.astype(np.float64))
if not np.array_equal(leech_q2, leech_q):
    diff = np.where(np.any(leech_q2 != leech_q, axis=1))[0]
    fails.append(f"Leech NOT idempotent at rows {diff.tolist()}")
else:
    print(f"[ok] Leech idempotent: Q(Q(x)) == Q(x)")

# Leech minimal-norm sanity: nonzero decoded points have norm^2 >= 32 (min norm)
norms = np.sum(leech_q.astype(np.int64) ** 2, axis=1)
nz = norms[norms > 0]
if nz.size and nz.min() < 32:
    fails.append(f"Leech decoded sub-minimal norm^2 {int(nz.min())} < 32")
else:
    print(f"[ok] Leech nonzero points respect min norm^2>=32 (min seen {int(nz.min()) if nz.size else 'n/a'})")


# ---- shape/error validation ----
try:
    lvq.nearest_e8_batch(np.zeros((3, 7)))
    fails.append("E8 wrong-dim did not raise")
except ValueError:
    print("[ok] E8 wrong-dim raises ValueError")

# ---- larger random batch throughput smoke (GIL released) ----
big = np.random.RandomState(7).uniform(-4, 4, size=(2000, 24))
bq = lvq.nearest_leech_batch(big)
bq2 = lvq.nearest_leech_batch(bq.astype(np.float64))
if not np.array_equal(bq, bq2):
    fails.append("Leech batch-2000 not idempotent")
else:
    print("[ok] Leech batch=2000 idempotent (parallel path)")


if fails:
    print("\nFAILURES:")
    for f in fails:
        print("  -", f)
    sys.exit(1)
print("\nALL PARITY + CORRECTNESS CHECKS PASSED")
